import test from 'node:test';
import assert from 'node:assert/strict';
import { decodeBase64Url } from '../src/base64url.mjs';
import { parseBlobLocator } from '../src/blob-locator.mjs';

test('the shared decoder rejects padding and the standard base64 alphabet', () => {
  assert.throws(() => decodeBase64Url('AQ=='), /canonical|base64url/i);
  assert.throws(() => decodeBase64Url('A+E'), /canonical|base64url/i);
});

test('locators reject padded aliases of a 16-byte id', () => {
  assert.throws(
    () => parseBlobLocator('images:AAAAAAAAAAAAAAAAAAAAAA=='),
    /canonical|base64url/i,
  );
});
